import React, { Suspense, lazy } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import ErrorBoundary from './components/ErrorBoundary';
import Login from './components/Login';
import Footer from './components/Footer';
import { ToastContainer } from 'react-toastify';
import 'bootstrap/dist/css/bootstrap.min.css';
import 'react-toastify/dist/ReactToastify.css';

// Lazy load components for better performance
const Dashboard = lazy(() => import('./components/Dashboard'));
const Register = lazy(() => import('./components/Register'));
const RFIDIntegration = lazy(() => import('./components/RFIDIntegration'));
const Inventory = lazy(() => import('./components/Inventory'));
const UploadRFID = lazy(() => import('./components/UploadRFID'));
const RFIDTransactions = lazy(() => import('./components/RFIDTransactions'));
const NotFound = lazy(() => import('./components/NotFound'));

// Protected route authentication check
const isAuthenticated = () => !!localStorage.getItem('token');

// Loading component
const LoadingFallback = () => (
  <div style={{
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '100vh',
    background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)'
  }}>
    <div className="spinner-border text-primary" role="status">
      <span className="visually-hidden">Loading...</span>
    </div>
  </div>
);

function App() {
  return (
    <ErrorBoundary>
      <Router>
        <div style={{
          minHeight: '100vh',
          display: 'flex',
          flexDirection: 'column',
          background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)'
        }}>
          <Suspense fallback={<LoadingFallback />}>
            <Routes>
              <Route path="/login" element={
                <div className="page-wrapper">
                  <Login />
                  <Footer />
                </div>
              } />
              <Route path="/register" element={
                <div className="page-wrapper">
                  <Register />
                  <Footer />
                </div>
              } />
              <Route path="/dashboard" element={
                isAuthenticated() ? (
                  <div className="page-wrapper">
                    <div className="route-transition content-fade-in">
                      <Dashboard />
                    </div>
                  </div>
                ) : <Navigate to="/login" />
              } />
              <Route path="/rfid-integration" element={
                isAuthenticated() ? (
                  <div className="page-wrapper">
                    <div className="route-transition content-fade-in">
                      <RFIDIntegration />
                    </div>
                  </div>
                ) : <Navigate to="/login" />
              } />
              <Route path="/inventory" element={
                isAuthenticated() ? (
                  <div className="page-wrapper">
                    <div className="route-transition content-fade-in">
                      <Inventory />
                    </div>
                  </div>
                ) : <Navigate to="/login" />
              } />
              <Route path="/upload-rfid" element={
                isAuthenticated() ? (
                  <div className="page-wrapper">
                    <div className="route-transition content-fade-in">
                      <UploadRFID />
                    </div>
                  </div>
                ) : <Navigate to="/login" />
              } />
              <Route path="/rfid-transactions" element={
                isAuthenticated() ? (
                  <div className="page-wrapper">
                    <div className="route-transition content-fade-in">
                      <RFIDTransactions />
                    </div>
                  </div>
                ) : <Navigate to="/login" />
              } />
              <Route path="/" element={<Navigate to="/dashboard" replace />} />
              <Route path="*" element={<NotFound />} />
            </Routes>
          </Suspense>
        </div>
        <ToastContainer 
          position="bottom-right"
          autoClose={3000}
          hideProgressBar={false}
          newestOnTop
          closeOnClick
          rtl={false}
          pauseOnFocusLoss
          draggable
          pauseOnHover
          theme="light"
          className="smooth-scroll"
        />
      </Router>
    </ErrorBoundary>
  );
}

export default App;
